// ── Fall 1: Trisomie 21 ──────────────────────────────────────────
1: [
  { q: 'Welche Aussage zur Trisomie 21 ist FALSCH?', choices: ['~95% sind freie Trisomien, davon ~80% durch Non-Disjunction in muetterlicher Meiose I', 'Das Wiederholungsrisiko bei freier Trisomie betraegt ca. 25%', 'AVSD ist der charakteristischste Herzfehler', 'Das Risiko steigt exponentiell mit muetterlichem Alter ab 35'], answer: 1, explain: 'FALSCH ist 25%. Das Wiederholungsrisiko bei freier Trisomie 21 betraegt ~1% + altersabhaengiges Basisrisiko. 25% waere autosomal rezessiv.' },
  { q: 'Eine 28-jährige Erstgebärende hat ein auffälliges Ersttrimesterscreening (Risiko 1:150 für Trisomie 21). NIPT bestätigt hohes Risiko. Nächster Schritt?', choices: ['Amniozentese/CVS zur Bestätigung (NIPT ist Screening, nicht diagnostisch!)', 'Diagnose Down-Syndrom mitteilen und Beratung', 'NIPT wiederholen in 4 Wochen', 'Sofort Karyotyp aus mütterlichem Blut'], answer: 0, explain: 'NIPT: Sensitivitaet ~99% fuer T21, aber PPV ist praevalenzabhaengig (~90-95% bei Hochrisiko, ~50-80% bei Niedrigrisiko-Population). Screening, NICHT diagnostisch! Vor irreversibler Entscheidung: invasive Bestaetigung (Amnio/CVS).' },
  { q: 'Bei einem Kind mit V.a. Down-Syndrom zeigt die Routine-FISH (lokusspezifische Sonde 21q22) 3 Signale. Warum reicht das nicht zur vollstaendigen Diagnostik?', choices: ['Routine-FISH mit Lokus-Sonde zeigt nur Kopienzahl, nicht ob frei oder transloziert — Karyotyp (oder WCP-FISH) noetig fuer Mechanismus', 'FISH ist generell unzuverlaessig', 'FISH zeigt keine Mosaike', 'FISH ist veraltet'], answer: 0, explain: 'Standard-FISH fuer Down nutzt eine lokusspezifische Sonde (DSCR, 21q22): zaehlt nur Kopien. Karyotyp oder WCP-FISH (Painting-Sonden fuer Chr 14+21) zeigt die Translokation. Translokations-Down (~4%): Wiederholungsrisiko bis 100% bei rob(21;21)! Mechanismus entscheidend.' },
  { q: 'Welches maligne Erkrankungsrisiko ist bei Kindern mit Down-Syndrom am stärksten erhöht?', choices: ['Akute megakaryoblastische Leukämie (AMKL/AML M7) — 500× erhöht', 'Retinoblastom', 'Neuroblastom', 'Wilms-Tumor'], answer: 0, explain: 'AMKL: 500× erhöht bei Down. Auch ALL ~20× erhöht. Dagegen: solide Tumoren sind bei Down SELTENER (Tumorsuppressor-Effekt durch Trisomie 21?).' },
  { q: 'Eine 42-jaehrige Schwangere fragt nach dem altersabhaengigen Risiko fuer Trisomie 21 bei Geburt. Korrekte Angabe?', choices: ['~1:55', '~1:150', '~1:350', '~1:700'], answer: 0, explain: 'Mit 42: ~1:55 bei Geburt (Hook/Hecht Daten). Mit 35: ~1:350. Mit 25: ~1:1250. Mit 45: ~1:30. Die Risikokurve steigt nach 35 exponentiell.' }
],

// ── Fall 2: Trisomie 18 ──────────────────────────────────────────
2: [
  { q: 'Welche Konstellation im Ersttrimesterscreening ist typisch für Trisomie 18?', choices: ['NT erhöht, freies beta-hCG erniedrigt, PAPP-A erniedrigt', 'NT normal, beta-hCG erhöht, PAPP-A erhöht', 'NT erhöht, beta-hCG erhöht, PAPP-A normal', 'Alles normal'], answer: 0, explain: 'Trisomie 18: BEIDE Marker erniedrigt (beta-hCG + PAPP-A) + NT erhöht. Trisomie 21: beta-hCG erhöht, PAPP-A erniedrigt. Wichtiger Unterschied!' },
  { q: 'Ein Paar hat ein Kind mit Trisomie 18 bekommen. In der nächsten Schwangerschaft zeigt der NIPT "low risk" für alle Trisomien. Welche Beratung ist korrekt?', choices: ['NIPT für Trisomie 18 hat niedrigeren PPV als für T21 — falsch-negative sind möglich, Sono-Kontrolle weiterhin wichtig', 'NIPT ist 100% sicher, keine weitere Diagnostik nötig', 'Nur relevant wenn Mutter >35 Jahre', 'NIPT erkennt nur Trisomie 21'], answer: 0, explain: 'NIPT: Sensitivitaet ~97% fuer T18 (vs. ~99% fuer T21). PPV fuer T18 deutlich niedriger (~40-85%) wegen geringerer Praevalenz. Falsch-negativ bei confined placental mosaicism moeglich. Sono-Kontrolle bleibt essentiell.' },
  { q: 'Welcher Ultraschallbefund im 2. Trimenon ist am spezifischsten für Trisomie 18?', choices: ['Strawberry-shaped head (erdbeerförmiger Schädel) + Plexus-choroideus-Zysten + überkreuzte Finger', 'Nur Wachstumsretardierung', 'Megacisterna magna allein', 'Erhöhte Nackentransparenz allein'], answer: 0, explain: 'Erdbeer-Schädel (prominentes Okziput), Plexus-choroideus-Zysten (~50%), überkreuzte Finger, Omphalozele, singuläre Nabelarterie = Ultraschall-Kombination hochspezifisch.' },
  { q: 'Welche ethische Besonderheit gilt für Trisomie 18 im Vergleich zu Trisomie 21?', choices: ['Letale Prognose verändert die Beratungssituation — palliativer Ansatz vs. lebenslange Betreuung', 'Kein Unterschied in der Beratung', 'Trisomie 18 ist therapierbar', 'Trisomie 18 hat bessere Prognose'], answer: 0, explain: 'T18: >90% sterben im 1. Jahr. T21: Lebenserwartung >60 Jahre. Perinatalpalliatives Konzept vs. Therapieplanung — fundamental andere Beratungssituation.' },
  { q: 'Mosaik-Trisomie 18 wird auf der Amniozentese diagnostiziert. Confined Placental Mosaicism (CPM) muss ausgeschlossen werden. Warum?', choices: ['CVS zeigt den Trophoblasten-Karyotyp, nicht den fetalen — CPM kann falsch-positiv sein; Amnio gilt als zuverlässiger', 'CPM gibt es bei Trisomie 18 nicht', 'Amnio ist unzuverlässiger als CVS', 'Mosaik ist immer im Fetus'], answer: 0, explain: 'Bei CVS: Trisomie kann auf die Plazenta beschränkt sein (CPM Typ III). Amnio reflektiert den Fetus besser. Bei Mosaik-Befund: Kordozentese als Goldstandard erwägen.' }
],

// ── Fall 6: Turner 45,X ──────────────────────────────────────────
6: [
  { q: 'Eine Turner-Patientin plant eine Schwangerschaft mit Eizellspende. Welche Voruntersuchung ist ABSOLUT OBLIGAT?', choices: ['Kardio-MRT mit Aortenwurzel-Index (Aortendissektion-Risiko in SS!)', 'Nur gynäkologische Untersuchung', 'Kein besonderes Screening nötig', 'Nur Blutdruck-Messung'], answer: 0, explain: 'Aortenwurzel-Index (ASI) >25mm/m² KOF = KONTRAINDIKATION für Schwangerschaft! Turner-Patientinnen haben 2% Aortendissektionsrisiko in der SS (vs. 0.0003% normal).' },
  { q: 'Welche Aussage zu Wachstumshormon bei Turner ist KORREKT?', choices: ['Beginne so früh wie möglich — jedes Jahr Verzögerung kostet ~1cm Endgröße', 'Erst ab Pubertätsalter beginnen', 'Nur bei GH-Mangel im Stimulationstest', 'Wachstumshormon ist bei Turner kontraindiziert'], answer: 0, explain: 'GH bei Turner: KEINE GH-Defizienz nötig (SHOX-Haploinsuffizienz ist der Mechanismus). Früher Beginn (ab 4-6 Jahre) = besserer Endgrößen-Gewinn (~5-8 cm).' },
  { q: 'Bei einer 16-jährigen Turner-Patientin wird ein kryptisches Y-Fragment (SRY+) auf Microarray detektiert. Welche Konsequenz?', choices: ['Prophylaktische Gonadektomie wegen 15-30% Gonadoblastom-Risiko', 'Nur beobachten', 'Testosteron-Therapie', 'Hormonelle Stimulation der Gonaden'], answer: 0, explain: 'Y-Material + Gonadendysgenesie → Gonadoblastom-Risiko 15-30%. Prophylaktische Gonadektomie ist Standard. Vor OP: MRT zum Gonadennachweis.' },
  { q: 'Welches Antibiotikum erfordert bei Turner-Patientinnen besondere Vorsicht?', choices: ['Fluorchinolone (Aortenaneurysma-/Dissektionsrisiko bei vorbestehender Aortopathie)', 'Penicillin', 'Cephalosporine', 'Makrolide'], answer: 0, explain: 'FDA Black Box Warning: Fluorchinolone erhöhen Aortenruptur-Risiko. Bei Turner mit bereits erhöhtem Aorten-Risiko: doppelte Gefährdung. Vermeiden wenn möglich.' },
  { q: 'Welche endokrinologische Langzeitkomplikation bei Turner wird am häufigsten übersehen?', choices: ['Hashimoto-Thyreoiditis (~30%, jährliches TSH-Screening)', 'Diabetes Typ 1', 'Morbus Addison', 'Hyperthyreose'], answer: 0, explain: 'Hashimoto: ~30% der Turner. Oft subklinisch. Jährliche TSH/fT4/TPO-AK-Kontrolle lebenslang. Auch Zöliakie gehäuft (~5%), jährliches Screening empfohlen.' }
],

// ── Fall 7: Klinefelter 47,XXY ───────────────────────────────────
